#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";

const root = process.cwd();

const files = {
  route: path.join(root, "server/routes/quoteDossiers.js"),
  enrichment: path.join(root, "server/services/quote-dossiers/quoteDossierEnrichmentService.js"),
  pdf: path.join(root, "server/services/quote-dossiers/quoteDossierPdfService.js"),
  trusted: path.join(root, "server/services/quote-dossiers/quoteDossierTrustedSources.js"),
  web: path.join(root, "server/services/quote-dossiers/quoteDossierWebEnrichmentService.js"),
  assets: path.join(root, "server/services/quote-dossiers/assets"),
};

function fail(message) {
  console.error(`❌ ${message}`);
  process.exit(1);
}

function write(filePath, content) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content, "utf8");
}

function copyAssets() {
  const sourceDir = path.join(root, "scripts/maintenance/assets/quote-dossier-products");

  if (!fs.existsSync(sourceDir)) {
    fail(`Pasta de assets não encontrada: ${path.relative(root, sourceDir)}`);
  }

  fs.mkdirSync(files.assets, { recursive: true });

  for (const entry of fs.readdirSync(sourceDir)) {
    const from = path.join(sourceDir, entry);
    const to = path.join(files.assets, entry);

    if (fs.statSync(from).isFile()) {
      fs.copyFileSync(from, to);
    }
  }
}

write(files.route, "import { extractTextFromPdfBase64 } from \"../services/quote-dossiers/pdfTextService.js\";\nimport { parseQuoteDossierFromText } from \"../services/quote-dossiers/quoteDossierParser.js\";\nimport { generateQuoteDossierPdf } from \"../services/quote-dossiers/quoteDossierPdfService.js\";\nimport { enrichQuoteDossier } from \"../services/quote-dossiers/quoteDossierEnrichmentService.js\";\nimport { webEnrichmentStatus } from \"../services/quote-dossiers/quoteDossierWebEnrichmentService.js\";\n\nexport const QUOTE_DOSSIER_RUNTIME_VERSION = \"quote-dossier-serious-runtime-v3\";\n\nfunction requireString(value, field, { min = 1, max = 500 } = {}) {\n  const text = String(value || \"\").trim();\n\n  if (text.length < min) {\n    throw new Error(`${field} obrigat\u00f3rio.`);\n  }\n\n  if (text.length > max) {\n    throw new Error(`${field} demasiado longo.`);\n  }\n\n  return text;\n}\n\nfunction safeFilename(value = \"\") {\n  return String(value || \"dossier-orcamento\")\n    .normalize(\"NFD\")\n    .replace(/[\\u0300-\\u036f]/g, \"\")\n    .replace(/[^a-zA-Z0-9._-]+/g, \"-\")\n    .replace(/^-+|-+$/g, \"\")\n    .toLowerCase()\n    .slice(0, 120) || \"dossier-orcamento\";\n}\n\nfunction serializeError(error) {\n  return {\n    message: error?.message || String(error || \"Erro desconhecido.\"),\n    name: error?.name || \"Error\",\n  };\n}\n\nexport function registerQuoteDossierRoutes(app, { requireAuth }) {\n  app.get(\"/api/orcamentos-dossiers/version\", (req, res) => {\n    return res.json({\n      ok: true,\n      version: QUOTE_DOSSIER_RUNTIME_VERSION,\n      webEnrichment: webEnrichmentStatus(),\n    });\n  });\n\n  app.post(\"/api/orcamentos-dossiers/extract\", requireAuth, async (req, res) => {\n    try {\n      const filename = requireString(req.body?.filename || \"orcamento.pdf\", \"filename\", { min: 1, max: 220 });\n      const base64Pdf = requireString(req.body?.pdfBase64, \"pdfBase64\", { min: 20, max: 90_000_000 });\n\n      const extracted = await extractTextFromPdfBase64(base64Pdf);\n      const parsedDossier = parseQuoteDossierFromText(extracted.text, { filename });\n      const dossier = await enrichQuoteDossier(parsedDossier);\n\n      return res.json({\n        ok: true,\n        version: QUOTE_DOSSIER_RUNTIME_VERSION,\n        dossier,\n        enrichmentSummary: dossier.enrichmentSummary,\n        pages: extracted.pages,\n        engine: extracted.engine || \"unknown\",\n      });\n    } catch (error) {\n      console.error(\"[quote-dossiers] extract error:\", error);\n\n      return res.status(400).json({\n        ok: false,\n        version: QUOTE_DOSSIER_RUNTIME_VERSION,\n        error: error?.message || \"Erro ao extrair or\u00e7amento.\",\n        details: serializeError(error),\n      });\n    }\n  });\n\n  app.post(\"/api/orcamentos-dossiers/generate\", requireAuth, async (req, res) => {\n    try {\n      const dossier = req.body?.dossier || {};\n      const items = Array.isArray(req.body?.items) ? req.body.items : [];\n\n      const enrichedDossier = await enrichQuoteDossier({ ...dossier, items });\n      const pdfBuffer = await generateQuoteDossierPdf({\n        dossier: enrichedDossier,\n        items: enrichedDossier.items,\n      });\n\n      const filename = safeFilename(`${enrichedDossier.budgetNumber || \"orcamento\"}-dossier-tecnico.pdf`);\n\n      res.setHeader(\"Content-Type\", \"application/pdf\");\n      res.setHeader(\"Content-Disposition\", `attachment; filename=\"${filename}\"`);\n      res.setHeader(\"Content-Length\", String(pdfBuffer.length));\n      res.setHeader(\"X-Quote-Dossier-Version\", QUOTE_DOSSIER_RUNTIME_VERSION);\n      res.setHeader(\"X-Quote-Dossier-Enrichment\", JSON.stringify(enrichedDossier.enrichmentSummary || {}));\n\n      return res.send(pdfBuffer);\n    } catch (error) {\n      console.error(\"[quote-dossiers] generate error:\", error);\n\n      return res.status(400).json({\n        ok: false,\n        version: QUOTE_DOSSIER_RUNTIME_VERSION,\n        error: error?.message || \"Erro ao gerar dossier PDF.\",\n        details: serializeError(error),\n      });\n    }\n  });\n}\n");
write(files.enrichment, "import fs from \"node:fs\";\nimport path from \"node:path\";\nimport { fileURLToPath } from \"node:url\";\nimport { enrichItemFromVerifiedWeb } from \"./quoteDossierWebEnrichmentService.js\";\n\nconst __filename = fileURLToPath(import.meta.url);\nconst __dirname = path.dirname(__filename);\nconst ASSET_DIR = path.join(__dirname, \"assets\");\n\nfunction clean(value = \"\") {\n  return String(value || \"\").replace(/\\s+/g, \" \").trim();\n}\n\nfunction normalizeEan(value = \"\") {\n  return clean(value).replace(/\\D+/g, \"\");\n}\n\nfunction uniqueLines(lines = []) {\n  const seen = new Set();\n\n  return lines\n    .map((line) => clean(line))\n    .filter(Boolean)\n    .filter((line) => {\n      const key = line.toLowerCase();\n\n      if (seen.has(key)) return false;\n\n      seen.add(key);\n      return true;\n    });\n}\n\nfunction loadAssetDataUrl(filename = \"\") {\n  if (!filename) return \"\";\n\n  const assetPath = path.join(ASSET_DIR, filename);\n\n  if (!fs.existsSync(assetPath)) return \"\";\n\n  const ext = path.extname(assetPath).toLowerCase();\n  const mimeType = ext === \".jpg\" || ext === \".jpeg\" ? \"image/jpeg\" : \"image/png\";\n  const base64 = fs.readFileSync(assetPath).toString(\"base64\");\n\n  return `data:${mimeType};base64,${base64}`;\n}\n\nfunction normalizeTitle(value = \"\") {\n  return clean(value)\n    .replace(/\\s+-\\s+/g, \" - \")\n    .replace(/\\bInd\\.\\b/gi, \"Indu\u00e7\u00e3o\")\n    .replace(/\\bM[a\u00e1]q\\.\\b/gi, \"M\u00e1quina\")\n    .replace(/\\bLoi[\u00e7c]a\\b/gi, \"Loi\u00e7a\");\n}\n\nconst CURATED_PRODUCTS = {\n  \"8059019105536\": {\n    title: \"CANDY CA38FL7N20WXB\",\n    category: \"Micro-ondas de encastre com grill\",\n    reference: \"CA38FL7N20WXB\",\n    imageAsset: \"8059019105536.png\",\n    description:\n      \"Micro-ondas de encastre Candy Wave 600, em acabamento preto, com capacidade de 20 litros e fun\u00e7\u00e3o micro-ondas com grill. \u00c9 uma solu\u00e7\u00e3o adequada para integra\u00e7\u00e3o em mobili\u00e1rio de cozinha, combinando aquecimento, descongela\u00e7\u00e3o e grelhador num equipamento compacto.\",\n    features: [\n      \"Capacidade total: 20 litros.\",\n      \"Fun\u00e7\u00e3o micro-ondas + grelhador.\",\n      \"Instala\u00e7\u00e3o de encastre e acabamento preto.\",\n      \"Comandos eletr\u00f3nicos e 5 n\u00edveis de pot\u00eancia.\",\n      \"Programa de descongela\u00e7\u00e3o e bloqueio para crian\u00e7as.\",\n      \"Prato girat\u00f3rio inclu\u00eddo.\",\n      \"Dimens\u00f5es aproximadas: 595 x 337 x 385 mm (L x P x A).\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n  \"8434778019674\": {\n    title: \"TEKA HLB 8300 BK\",\n    category: \"Forno multifun\u00e7\u00f5es de encastre\",\n    reference: \"111000053 / HLB 8300 BK\",\n    imageAsset: \"8434778019674.png\",\n    description:\n      \"Forno multifun\u00e7\u00f5es de encastre Teka HLB 8300, em vidro preto, indicado para utiliza\u00e7\u00e3o dom\u00e9stica di\u00e1ria. A capacidade interior de 71 litros e as 6 fun\u00e7\u00f5es de confe\u00e7\u00e3o permitem maior versatilidade na prepara\u00e7\u00e3o de refei\u00e7\u00f5es.\",\n    features: [\n      \"Forno multifun\u00e7\u00f5es com 6 fun\u00e7\u00f5es de confe\u00e7\u00e3o.\",\n      \"Capacidade total: 71 litros.\",\n      \"Sistema de limpeza HydroClean PRO.\",\n      \"Classe de efici\u00eancia energ\u00e9tica A+.\",\n      \"Instala\u00e7\u00e3o de encastre.\",\n      \"Acabamento em vidro preto.\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n  \"8434778012491\": {\n    title: \"TEKA IZC 64010 BK MSS\",\n    category: \"Placa de indu\u00e7\u00e3o\",\n    reference: \"IZC 64010 BK MSS\",\n    imageAsset: \"8434778012491.png\",\n    description:\n      \"Placa de indu\u00e7\u00e3o Teka com 4 zonas de cozinhado e controlo Touch Control MultiSlider. Foi concebida para instala\u00e7\u00e3o de encastre em bancada, oferecendo rapidez de aquecimento, programa\u00e7\u00e3o de tempo e fun\u00e7\u00f5es de seguran\u00e7a.\",\n    features: [\n      \"Placa de indu\u00e7\u00e3o com 4 zonas de cozinhado.\",\n      \"Touch Control MultiSlider com bloqueio de seguran\u00e7a.\",\n      \"Programador do tempo de cozinhado e detetor de recipiente.\",\n      \"2 zonas de \u00d8 185 mm e 2 zonas de \u00d8 150 mm.\",\n      \"Fun\u00e7\u00f5es Power Plus, bloqueio infantil e indicador de calor residual.\",\n      \"Pot\u00eancia m\u00e1xima nominal: 7200 W.\",\n      \"Dimens\u00f5es aproximadas: 600 x 510 x 58 mm (L x P x A); encastre: 560 x 490 x 54 mm.\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n  \"7333394034669\": {\n    title: \"AEG FSB34707Z\",\n    category: \"M\u00e1quina de lavar loi\u00e7a de encastre\",\n    reference: \"FSB34707Z\",\n    imageAsset: \"7333394034669.png\",\n    description:\n      \"M\u00e1quina de lavar loi\u00e7a AEG de encastre total, com 60 cm, pertencente \u00e0 S\u00e9rie 5000 AirDry. A tecnologia AirDry favorece a secagem natural atrav\u00e9s da abertura autom\u00e1tica da porta no final do ciclo.\",\n    features: [\n      \"M\u00e1quina de lavar loi\u00e7a de 60 cm para encastre total.\",\n      \"Capacidade indicada: 14 talheres.\",\n      \"Sistema AirDry, com abertura autom\u00e1tica da porta cerca de 10 cm na fase final de secagem.\",\n      \"Sensor de carga/sujidade para ajustar o ciclo de lavagem \u00e0s necessidades reais.\",\n      \"Programa r\u00e1pido de 30 minutos para lavagens mais curtas.\",\n      \"Classe de efici\u00eancia energ\u00e9tica C indicada para o modelo.\",\n      \"N\u00edvel de ru\u00eddo indicado por retalhistas verificados: 44 dB(A).\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n  \"8806097163985\": {\n    title: \"SAMSUNG RS70F64KETEF\",\n    category: \"Frigor\u00edfico americano Side by Side\",\n    reference: \"RS70F64KETEF\",\n    imageAsset: \"8806097163985.png\",\n    description:\n      \"Frigor\u00edfico americano Samsung em inox, com elevada capacidade de armazenamento e integra\u00e7\u00e3o SmartThings. \u00c9 indicado para utiliza\u00e7\u00e3o familiar, oferecendo grande volume \u00fatil e fun\u00e7\u00f5es de gest\u00e3o inteligente de energia.\",\n    features: [\n      \"Capacidade total indicada: 640 litros.\",\n      \"Volume aproximado: 420 litros no frigor\u00edfico e 220 litros no congelador.\",\n      \"Tecnologia SpaceMax para maior capacidade interior sem aumento significativo das dimens\u00f5es exteriores.\",\n      \"Conetividade Wi-Fi e integra\u00e7\u00e3o com SmartThings.\",\n      \"Modo Energia IA para apoio \u00e0 monitoriza\u00e7\u00e3o e gest\u00e3o do consumo.\",\n      \"Tecnologias de frio Samsung indicadas: All-Around Cooling, No Frost, Power Cool e Power Freeze.\",\n      \"Dimens\u00f5es aproximadas: 912 x 1784 x 726 mm (L x A x P).\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n  \"8806097064466\": {\n    title: \"SAMSUNG DV90DG52A0AEEP\",\n    category: \"M\u00e1quina de secar roupa com bomba de calor\",\n    reference: \"DV90DG52A0AEEP\",\n    imageAsset: \"8806097064466.png\",\n    description:\n      \"M\u00e1quina de secar roupa Samsung de 9 kg, com tecnologia de bomba de calor, orientada para uma secagem eficiente e para o cuidado dos tecidos. Integra fun\u00e7\u00f5es inteligentes atrav\u00e9s da aplica\u00e7\u00e3o SmartThings.\",\n    features: [\n      \"Capacidade de secagem: 9 kg.\",\n      \"Tecnologia de bomba de calor.\",\n      \"Fun\u00e7\u00e3o Hygiene Care para apoio \u00e0 higieniza\u00e7\u00e3o da roupa.\",\n      \"Conetividade Wi-Fi e controlo/monitoriza\u00e7\u00e3o atrav\u00e9s de SmartThings.\",\n      \"Modo Energia IA para acompanhamento do consumo energ\u00e9tico.\",\n      \"Motor Digital Inverter, tambor Diamond, luz interior no tambor e bloqueio para crian\u00e7as indicados por retalhistas verificados.\",\n      \"Consumo indicado por retalhista verificado: 105 kWh por 100 ciclos.\",\n    ],\n    sourceLabel: \"Cat\u00e1logo t\u00e9cnico validado internamente\",\n  },\n};\n\nfunction categoryFallback(description = \"\") {\n  const text = String(description || \"\").toLowerCase();\n\n  if (/micro|microondas|micro-ondas/.test(text)) return \"Micro-ondas de encastre\";\n  if (/chamin[e\u00e9]|exaustor|camp[\u00e2a]nula/.test(text)) return \"Chamin\u00e9/exaustor\";\n  if (/forno/.test(text)) return \"Forno multifun\u00e7\u00f5es\";\n  if (/placa|ind[.\\s]?/.test(text)) return \"Placa de indu\u00e7\u00e3o\";\n  if (/lavar.*loi[\u00e7c]a/.test(text)) return \"M\u00e1quina de lavar loi\u00e7a\";\n  if (/lava[-\\s]?loi[\u00e7c]a/.test(text)) return \"Lava-loi\u00e7a\";\n  if (/torneira|misturadora/.test(text)) return \"Torneira misturadora\";\n  if (/garrafeira|winechef|wine/.test(text)) return \"Garrafeira\";\n  if (/side by side|french door|frigor/.test(text)) return \"Frigor\u00edfico\";\n  if (/secar roupa/.test(text)) return \"M\u00e1quina de secar roupa\";\n\n  return \"Equipamento\";\n}\n\nfunction genericFeatures(item = {}) {\n  return uniqueLines([\n    item.reference ? `Refer\u00eancia/modelo identificado: ${item.reference}.` : \"\",\n    item.ean ? `EAN identificado: ${item.ean}.` : \"\",\n    \"Quantidade, pre\u00e7o e refer\u00eancia importados automaticamente do or\u00e7amento Primavera/ORC.\",\n    \"Confirmar medidas, requisitos de instala\u00e7\u00e3o, ventila\u00e7\u00e3o, liga\u00e7\u00f5es el\u00e9tricas/hidr\u00e1ulicas e compatibilidade com o mobili\u00e1rio existente.\",\n  ]);\n}\n\nfunction genericDescription(item = {}) {\n  const title = clean(item.title || item.description || item.rawDescription || item.reference || \"equipamento\");\n  const category = clean(item.category || categoryFallback(title));\n\n  return `${category} inclu\u00eddo no or\u00e7amento, identificado como ${title}. A informa\u00e7\u00e3o t\u00e9cnica, fotografia, medidas e requisitos de instala\u00e7\u00e3o devem ser confirmados antes da encomenda definitiva e da instala\u00e7\u00e3o.`;\n}\n\nfunction mergeItemWithCurated(item = {}, product = null) {\n  const ean = normalizeEan(item.ean);\n  const title = normalizeTitle(product?.title || item.title || item.description || item.rawDescription || item.reference || \"\");\n  const imageDataUrl = product?.imageAsset ? loadAssetDataUrl(product.imageAsset) : \"\";\n\n  const merged = {\n    ...item,\n    ean,\n    title,\n    description: title || item.description || \"\",\n    rawDescription: item.rawDescription || item.description || title,\n    category: product?.category || item.category || categoryFallback(title),\n    reference: product?.reference || item.reference || \"\",\n    technicalDescription: product?.description || item.technicalDescription || genericDescription({ ...item, title }),\n    features: uniqueLines(product?.features || item.features || genericFeatures({ ...item, title })),\n    imageDataUrl: item.imageDataUrl || imageDataUrl,\n    enrichment: {\n      status: product ? \"matched\" : \"generic\",\n      source: product ? \"curated_catalog\" : \"generic_fallback\",\n      confidence: product ? 0.98 : 0.35,\n      sourceLabel: product?.sourceLabel || \"Informa\u00e7\u00e3o gerada a partir do or\u00e7amento; requer valida\u00e7\u00e3o\",\n    },\n  };\n\n  if (!merged.features.length) {\n    merged.features = genericFeatures(merged);\n  }\n\n  return merged;\n}\n\nfunction itemMatchKeys(item = {}) {\n  return [\n    normalizeEan(item.ean),\n    clean(item.reference).toLowerCase(),\n    clean(item.title).toLowerCase(),\n    clean(item.description).toLowerCase(),\n    clean(item.rawDescription).toLowerCase(),\n  ].filter(Boolean);\n}\n\nfunction findCuratedProduct(item = {}) {\n  const keys = itemMatchKeys(item);\n\n  for (const key of keys) {\n    if (CURATED_PRODUCTS[key]) return CURATED_PRODUCTS[key];\n  }\n\n  for (const product of Object.values(CURATED_PRODUCTS)) {\n    const haystack = [\n      product.title,\n      product.reference,\n      product.category,\n      product.description,\n    ]\n      .join(\" \")\n      .toLowerCase();\n\n    if (keys.some((key) => key.length >= 5 && haystack.includes(key))) {\n      return product;\n    }\n  }\n\n  return null;\n}\n\nexport async function enrichQuoteDossier(dossier = {}) {\n  const items = Array.isArray(dossier.items) ? dossier.items : [];\n  const enrichedItems = [];\n\n  for (const item of items) {\n    const curated = findCuratedProduct(item);\n\n    if (curated) {\n      enrichedItems.push(mergeItemWithCurated(item, curated));\n      continue;\n    }\n\n    const webItem = await enrichItemFromVerifiedWeb(item);\n\n    if (webItem) {\n      enrichedItems.push(webItem);\n      continue;\n    }\n\n    enrichedItems.push(mergeItemWithCurated(item, null));\n  }\n\n  const matchedCount = enrichedItems.filter((item) => item.enrichment?.status === \"matched\").length;\n  const webCount = enrichedItems.filter((item) => [\"official_match\", \"verified_match\"].includes(item.enrichment?.status)).length;\n\n  return {\n    ...dossier,\n    items: enrichedItems,\n    enrichmentSummary: {\n      total: enrichedItems.length,\n      matched: matchedCount,\n      web: webCount,\n      generic: enrichedItems.length - matchedCount - webCount,\n      mode: String(process.env.QUOTE_DOSSIER_WEB_ENRICHMENT || \"\").toLowerCase() === \"1\"\n        ? \"curated_catalog_plus_verified_web_v3\"\n        : \"curated_catalog_v3\",\n    },\n  };\n}\n");
write(files.pdf, "import PDFDocument from \"pdfkit\";\n\nconst PAGE_MARGIN = 42;\nconst BRAND_COLOR = \"#24465f\";\nconst ACCENT_COLOR = \"#f97316\";\nconst LIGHT_BORDER = \"#d9dee6\";\nconst SOFT_BG = \"#f6f8fb\";\nconst TEXT_COLOR = \"#17202a\";\nconst MUTED = \"#657386\";\n\nfunction text(value = \"\") {\n  return String(value || \"\").trim();\n}\n\nfunction euro(value = \"\") {\n  const clean = text(value);\n\n  if (!clean) return \"\u2014\";\n  if (clean.includes(\"\u20ac\")) return clean;\n\n  return `${clean} \u20ac`;\n}\n\nfunction quantity(value = \"\") {\n  const clean = text(value);\n  if (!clean) return \"\u2014\";\n  if (/un\\.?$/i.test(clean)) return clean.replace(/1,00/i, \"1\");\n  return `${clean.replace(/,00$/, \"\")} un.`;\n}\n\nfunction safeTitle(value = \"\") {\n  return text(value).replace(/\\s+/g, \" \");\n}\n\nfunction cleanFeature(value = \"\") {\n  return text(value).replace(/^[-\u2022]\\s*/, \"\");\n}\n\nfunction parseImageDataUrl(dataUrl = \"\") {\n  const match = String(dataUrl || \"\").match(/^data:image\\/(png|jpeg|jpg|webp|avif);base64,(.+)$/i);\n\n  if (!match) return null;\n\n  return Buffer.from(match[2], \"base64\");\n}\n\nfunction drawHeader(doc, dossier = {}, pageTitle = \"\") {\n  const top = 24;\n\n  doc\n    .rect(PAGE_MARGIN, top, 86, 28)\n    .fill(ACCENT_COLOR);\n\n  doc\n    .fillColor(\"#ffffff\")\n    .font(\"Helvetica-Bold\")\n    .fontSize(15)\n    .text(\"expert\", PAGE_MARGIN, top + 7, { width: 86, align: \"center\" });\n\n  doc\n    .fillColor(MUTED)\n    .font(\"Helvetica\")\n    .fontSize(8.5)\n    .text(\n      [dossier.budgetNumber, pageTitle].filter(Boolean).join(\" - \"),\n      PAGE_MARGIN + 110,\n      top + 9,\n      { width: doc.page.width - PAGE_MARGIN * 2 - 110, align: \"right\" },\n    );\n\n  doc\n    .moveTo(PAGE_MARGIN, top + 42)\n    .lineTo(doc.page.width - PAGE_MARGIN, top + 42)\n    .strokeColor(\"#e2e8f0\")\n    .lineWidth(0.8)\n    .stroke();\n\n  doc.fillColor(TEXT_COLOR);\n}\n\nfunction drawFooter(doc, pageNumber) {\n  const y = doc.page.height - 34;\n\n  doc\n    .moveTo(PAGE_MARGIN, y - 10)\n    .lineTo(doc.page.width - PAGE_MARGIN, y - 10)\n    .strokeColor(\"#e2e8f0\")\n    .lineWidth(0.8)\n    .stroke();\n\n  doc\n    .fillColor(\"#7a8797\")\n    .font(\"Helvetica\")\n    .fontSize(8)\n    .text(\"Documento de caracter\u00edsticas dos equipamentos\", PAGE_MARGIN, y, {\n      width: 280,\n      align: \"left\",\n    })\n    .text(`P\u00e1gina ${pageNumber}`, doc.page.width - PAGE_MARGIN - 90, y, {\n      width: 90,\n      align: \"right\",\n    });\n\n  doc.fillColor(TEXT_COLOR);\n}\n\nfunction startPage(doc, dossier, pageTitle, pageNumber) {\n  doc.addPage();\n  drawHeader(doc, dossier, pageTitle);\n  drawFooter(doc, pageNumber);\n\n  return 86;\n}\n\nfunction drawSectionTitle(doc, title, x, y) {\n  doc\n    .fillColor(BRAND_COLOR)\n    .font(\"Helvetica-Bold\")\n    .fontSize(15)\n    .text(title, x, y);\n\n  doc.fillColor(TEXT_COLOR);\n  return y + 25;\n}\n\nfunction drawInfoTable(doc, rows = [], x, y, width, { labelWidth = 135, rowHeight = 24 } = {}) {\n  let currentY = y;\n\n  rows.forEach(([label, value]) => {\n    const valueText = text(value) || \"\u2014\";\n    const estimatedHeight = Math.max(rowHeight, doc.heightOfString(valueText, { width: width - labelWidth - 14 }) + 12);\n\n    doc\n      .rect(x, currentY, labelWidth, estimatedHeight)\n      .fillAndStroke(SOFT_BG, LIGHT_BORDER)\n      .rect(x + labelWidth, currentY, width - labelWidth, estimatedHeight)\n      .fillAndStroke(\"#ffffff\", LIGHT_BORDER);\n\n    doc\n      .fillColor(\"#2d3748\")\n      .font(\"Helvetica-Bold\")\n      .fontSize(9)\n      .text(label, x + 7, currentY + 8, { width: labelWidth - 14 });\n\n    doc\n      .fillColor(TEXT_COLOR)\n      .font(\"Helvetica\")\n      .fontSize(9.5)\n      .text(valueText, x + labelWidth + 8, currentY + 7, { width: width - labelWidth - 16 });\n\n    currentY += estimatedHeight;\n  });\n\n  doc.fillColor(TEXT_COLOR);\n  return currentY;\n}\n\nfunction drawParagraph(doc, value, x, y, width, options = {}) {\n  const fontSize = options.fontSize || 10.2;\n  const lineGap = options.lineGap ?? 2;\n  const maxHeight = options.maxHeight || 90;\n  const content = text(value);\n  if (!content) return y;\n\n  doc\n    .font(\"Helvetica\")\n    .fontSize(fontSize)\n    .fillColor(TEXT_COLOR);\n\n  const height = Math.min(doc.heightOfString(content, { width, lineGap }), maxHeight);\n\n  doc.text(content, x, y, {\n    width,\n    lineGap,\n    height,\n    ellipsis: true,\n  });\n\n  return y + height + 8;\n}\n\nfunction uniqueFeatures(features = []) {\n  const seen = new Set();\n\n  return (Array.isArray(features) ? features : String(features || \"\").split(\"\\n\"))\n    .map((feature) => text(feature))\n    .filter(Boolean)\n    .filter((feature) => {\n      const key = feature.toLowerCase();\n      if (seen.has(key)) return false;\n      seen.add(key);\n      return true;\n    });\n}\n\nfunction drawBullets(doc, features = [], x, y, width, { maxItems = 8 } = {}) {\n  let currentY = y;\n\n  uniqueFeatures(features)\n    .slice(0, maxItems)\n    .forEach((feature) => {\n      const bullet = cleanFeature(feature);\n      if (!bullet) return;\n\n      const height = Math.min(doc.heightOfString(bullet, { width: width - 16, lineGap: 1 }), 26);\n\n      doc\n        .font(\"Helvetica\")\n        .fontSize(9.5)\n        .fillColor(TEXT_COLOR)\n        .text(\"\u2022\", x, currentY, { width: 10 })\n        .text(bullet, x + 14, currentY, {\n          width: width - 16,\n          lineGap: 1,\n          height,\n          ellipsis: true,\n        });\n\n      currentY += height + 5;\n    });\n\n  return currentY;\n}\n\nfunction drawImageBox(doc, item, x, y, width, height) {\n  doc\n    .rect(x, y, width, height)\n    .fillAndStroke(\"#ffffff\", LIGHT_BORDER);\n\n  const imageBuffer = parseImageDataUrl(item.imageDataUrl);\n\n  if (imageBuffer) {\n    try {\n      doc.image(imageBuffer, x + 12, y + 12, {\n        fit: [width - 24, height - 24],\n        align: \"center\",\n        valign: \"center\",\n      });\n      return;\n    } catch (error) {\n      console.warn(\"[quote-dossiers] failed to render image:\", error?.message || error);\n    }\n  }\n\n  doc\n    .fillColor(\"#8b95a5\")\n    .font(\"Helvetica\")\n    .fontSize(9)\n    .text(\"Fotografia n\u00e3o encontrada automaticamente\", x, y + height / 2 - 5, {\n      width,\n      align: \"center\",\n    });\n\n  doc.fillColor(TEXT_COLOR);\n}\n\nfunction drawSummaryPage(doc, dossier = {}, pageNumber) {\n  let y = startPage(doc, dossier, \"Caracter\u00edsticas dos equipamentos\", pageNumber);\n  const x = PAGE_MARGIN;\n  const width = doc.page.width - PAGE_MARGIN * 2;\n\n  y += 28;\n\n  doc\n    .fillColor(BRAND_COLOR)\n    .font(\"Helvetica-Bold\")\n    .fontSize(23)\n    .text(\"Caracter\u00edsticas dos Equipamentos\", x + 50, y, { width: width - 100, align: \"center\" });\n\n  y += 28;\n\n  doc\n    .fillColor(\"#6b7280\")\n    .font(\"Helvetica\")\n    .fontSize(10)\n    .text(\n      [dossier.budgetNumber, dossier.customerName ? `Cliente: ${dossier.customerName}` : \"\", dossier.date ? `Data: ${dossier.date}` : \"\"]\n        .filter(Boolean)\n        .join(\" | \"),\n      x,\n      y,\n      { width, align: \"center\" },\n    );\n\n  y += 30;\n\n  const rows = [\n    [\"Or\u00e7amento\", dossier.budgetNumber],\n    [\"Cliente\", dossier.customerName],\n    [\"Data do or\u00e7amento\", dossier.date],\n    [\"Total do or\u00e7amento\", euro(dossier.total)],\n    [\"N.\u00ba de equipamentos/elementos\", `${(dossier.items || []).length} equipamento(s)`],\n  ];\n\n  y = drawInfoTable(doc, rows, x + 8, y, width - 16, { labelWidth: 160, rowHeight: 23 }) + 28;\n\n  y = drawSectionTitle(doc, \"Enquadramento\", x, y);\n  y = drawParagraph(\n    doc,\n    \"O presente documento re\u00fane, de forma separada e organizada, a identifica\u00e7\u00e3o e as caracter\u00edsticas dos equipamentos constantes do or\u00e7amento. A informa\u00e7\u00e3o encontra-se estruturada de modo claro e objetivo, permitindo a consulta individual de cada elemento inclu\u00eddo.\",\n    x,\n    y,\n    width,\n    { maxHeight: 70 },\n  );\n\n  y = drawSectionTitle(doc, \"Observa\u00e7\u00f5es do or\u00e7amento\", x, y + 6);\n  const notes = uniqueFeatures([\n    \"Condi\u00e7\u00e3o de pagamento: pronto pagamento.\",\n    dossier.notes || \"\",\n  ]);\n  y = drawBullets(doc, notes, x, y, width, { maxItems: 3 }) + 8;\n\n  y = drawSectionTitle(doc, \"Equipamentos inclu\u00eddos\", x, y);\n\n  (dossier.items || []).slice(0, 18).forEach((item, index) => {\n    doc\n      .font(\"Helvetica\")\n      .fontSize(10)\n      .fillColor(TEXT_COLOR)\n      .text(`${index + 1}. ${safeTitle(item.title || item.description || item.reference)}`, x, y, { width });\n    y += 19;\n  });\n}\n\nfunction drawProductPage(doc, dossier = {}, item = {}, index = 0, pageNumber = 1) {\n  let y = startPage(doc, dossier, \"Caracter\u00edsticas dos equipamentos\", pageNumber);\n  const x = PAGE_MARGIN;\n  const width = doc.page.width - PAGE_MARGIN * 2;\n\n  y += 34;\n\n  const title = `${index + 1}. ${safeTitle(item.title || item.description || item.reference || \"Equipamento\")}`;\n\n  doc\n    .fillColor(BRAND_COLOR)\n    .font(\"Helvetica-Bold\")\n    .fontSize(18)\n    .text(title, x, y, { width });\n\n  y += 32;\n\n  y = drawInfoTable(\n    doc,\n    [\n      [\"Categoria\", item.category],\n      [\"Refer\u00eancia\", item.reference],\n      [\"EAN\", item.ean],\n      [\"Quantidade\", quantity(item.quantity)],\n      [\"Valor no or\u00e7amento\", euro(item.total || item.unitPrice)],\n    ],\n    x,\n    y,\n    width,\n    { labelWidth: 118, rowHeight: 23 },\n  ) + 10;\n\n  doc\n    .fillColor(\"#2d3748\")\n    .font(\"Helvetica-Bold\")\n    .fontSize(9.5)\n    .text(\"Fotografia do equipamento\", x, y);\n\n  y += 14;\n\n  drawImageBox(doc, item, x, y, width, 125);\n  y += 142;\n\n  doc\n    .fillColor(\"#2d3748\")\n    .font(\"Helvetica-Bold\")\n    .fontSize(9.8)\n    .text(\"Descri\u00e7\u00e3o geral\", x, y);\n\n  y += 16;\n\n  y = drawParagraph(\n    doc,\n    item.technicalDescription || item.description || item.rawDescription,\n    x,\n    y,\n    width,\n    { fontSize: 9.7, maxHeight: 74 },\n  );\n\n  doc\n    .fillColor(\"#2d3748\")\n    .font(\"Helvetica-Bold\")\n    .fontSize(9.8)\n    .text(\"Principais caracter\u00edsticas\", x, y + 4);\n\n  y += 22;\n  drawBullets(doc, item.features, x + 8, y, width - 8, { maxItems: 8 });\n}\n\nfunction drawFinalPage(doc, dossier = {}, pageNumber = 1) {\n  let y = startPage(doc, dossier, \"Nota final\", pageNumber);\n  const x = PAGE_MARGIN;\n  const width = doc.page.width - PAGE_MARGIN * 2;\n\n  y += 34;\n  y = drawSectionTitle(doc, \"Nota final\", x, y);\n\n  y = drawParagraph(\n    doc,\n    \"As caracter\u00edsticas apresentadas foram organizadas automaticamente com base no or\u00e7amento, no cat\u00e1logo t\u00e9cnico dispon\u00edvel e em informa\u00e7\u00e3o validada internamente. Antes da encomenda definitiva e da instala\u00e7\u00e3o, recomenda-se a confirma\u00e7\u00e3o das medidas, requisitos de encastre, ventila\u00e7\u00e3o, liga\u00e7\u00f5es el\u00e9tricas/hidr\u00e1ulicas, acess\u00f3rios necess\u00e1rios e compatibilidade com o mobili\u00e1rio existente.\",\n    x,\n    y,\n    width,\n    { maxHeight: 120 },\n  );\n\n  y = drawSectionTitle(doc, \"Fontes e valida\u00e7\u00e3o\", x, y + 16);\n\n  const sourceLines = uniqueFeatures([\n    \"Or\u00e7amento Primavera/ORC carregado pelo utilizador.\",\n    \"Cat\u00e1logo t\u00e9cnico interno/curado quando dispon\u00edvel.\",\n    \"Itens sem correspond\u00eancia de cat\u00e1logo devem ser revistos antes da entrega ao cliente.\",\n    ...(dossier.items || []).map((item) => item.enrichment?.sourceLabel).filter(Boolean),\n  ]);\n\n  drawBullets(doc, sourceLines, x, y, width, { maxItems: 12 });\n}\n\nexport async function generateQuoteDossierPdf({ dossier = {}, items = [] } = {}) {\n  return new Promise((resolve, reject) => {\n    const finalDossier = {\n      ...dossier,\n      items: Array.isArray(items) ? items : [],\n    };\n\n    const doc = new PDFDocument({\n      size: \"A4\",\n      margin: PAGE_MARGIN,\n      autoFirstPage: false,\n      bufferPages: false,\n      info: {\n        Title: `${finalDossier.budgetNumber || \"Or\u00e7amento\"} - Caracter\u00edsticas dos equipamentos`,\n        Author: \"PromoPilot\",\n        Subject: \"Dossier t\u00e9cnico autom\u00e1tico\",\n      },\n    });\n\n    const chunks = [];\n\n    doc.on(\"data\", (chunk) => chunks.push(chunk));\n    doc.on(\"error\", reject);\n    doc.on(\"end\", () => resolve(Buffer.concat(chunks)));\n\n    let pageNumber = 1;\n    drawSummaryPage(doc, finalDossier, pageNumber);\n\n    finalDossier.items.forEach((item, index) => {\n      pageNumber += 1;\n      drawProductPage(doc, finalDossier, item, index, pageNumber);\n    });\n\n    pageNumber += 1;\n    drawFinalPage(doc, finalDossier, pageNumber);\n\n    doc.end();\n  });\n}\n");
write(files.trusted, "const OFFICIAL_DOMAINS_BY_BRAND = {\n  AEG: [\"aeg.pt\", \"aeg.com.pt\"],\n  BOSCH: [\"bosch-home.pt\", \"bosch-home.com\"],\n  CANDY: [\"candy-home.com\", \"candy.pt\"],\n  CASO: [\"caso-design.de\", \"caso-design.pt\"],\n  ELECTROLUX: [\"electrolux.pt\"],\n  LG: [\"lg.com\"],\n  SAMSUNG: [\"samsung.com\"],\n  SIEMENS: [\"siemens-home.bsh-group.com\", \"siemens-home.com\", \"siemens-home.pt\"],\n  TEKA: [\"teka.com\", \"teka.pt\"],\n  WHIRLPOOL: [\"whirlpool.pt\", \"whirlpool.eu\"],\n  ZANUSSI: [\"zanussi.pt\"],\n};\n\nconst VERIFIED_RETAILER_DOMAINS = [\n  \"worten.pt\",\n  \"radiopopular.pt\",\n  \"kuantokusta.pt\",\n  \"fnac.pt\",\n  \"elcorteingles.pt\",\n  \"mediamarkt.pt\",\n  \"amazon.es\",\n];\n\nfunction clean(value = \"\") {\n  return String(value || \"\").replace(/\\s+/g, \" \").trim();\n}\n\nexport function normalizeDomain(url = \"\") {\n  try {\n    return new URL(url).hostname.replace(/^www\\./i, \"\").toLowerCase();\n  } catch {\n    return \"\";\n  }\n}\n\nexport function inferBrandFromItem(item = {}) {\n  const value = clean(item.brand || item.title || item.description || item.rawDescription || item.reference);\n  const first = value.split(/\\s+/)[0]?.replace(/[^A-Za-z\u00c0-\u00ff0-9-]/g, \"\").toUpperCase();\n\n  if (first && OFFICIAL_DOMAINS_BY_BRAND[first]) return first;\n\n  for (const brand of Object.keys(OFFICIAL_DOMAINS_BY_BRAND)) {\n    if (value.toUpperCase().includes(brand)) return brand;\n  }\n\n  return first || \"\";\n}\n\nexport function officialDomainsForBrand(brand = \"\") {\n  const normalized = clean(brand).toUpperCase();\n  return OFFICIAL_DOMAINS_BY_BRAND[normalized] || [];\n}\n\nexport function trustedDomainsForItem(item = {}) {\n  const brand = inferBrandFromItem(item);\n  const official = officialDomainsForBrand(brand);\n\n  return [...official, ...VERIFIED_RETAILER_DOMAINS];\n}\n\nexport function isOfficialDomain(url = \"\", item = {}) {\n  const domain = normalizeDomain(url);\n  const brand = inferBrandFromItem(item);\n\n  return officialDomainsForBrand(brand).some((officialDomain) => (\n    domain === officialDomain || domain.endsWith(`.${officialDomain}`)\n  ));\n}\n\nexport function isVerifiedDomain(url = \"\", item = {}) {\n  const domain = normalizeDomain(url);\n\n  return trustedDomainsForItem(item).some((trustedDomain) => (\n    domain === trustedDomain || domain.endsWith(`.${trustedDomain}`)\n  ));\n}\n\nexport function sourcePriority(url = \"\", item = {}) {\n  if (isOfficialDomain(url, item)) return 1;\n  if (isVerifiedDomain(url, item)) return 2;\n  return 9;\n}\n\nexport function buildTrustedSearchQuery(item = {}) {\n  const brand = inferBrandFromItem(item);\n  const ean = clean(item.ean);\n  const reference = clean(item.reference || item.title || item.description || item.rawDescription);\n  const officialDomains = officialDomainsForBrand(brand);\n  const domainFilter = officialDomains.length ? `(${officialDomains.map((domain) => `site:${domain}`).join(\" OR \")})` : \"\";\n\n  return [\n    ean || reference,\n    brand && !reference.toUpperCase().includes(brand) ? brand : \"\",\n    \"caracter\u00edsticas ficha t\u00e9cnica imagem\",\n    domainFilter,\n  ]\n    .filter(Boolean)\n    .join(\" \");\n}\n\nexport function buildVerifiedSearchQuery(item = {}) {\n  const ean = clean(item.ean);\n  const reference = clean(item.reference || item.title || item.description || item.rawDescription);\n  const domains = trustedDomainsForItem(item).slice(0, 10);\n  const domainFilter = domains.length ? `(${domains.map((domain) => `site:${domain}`).join(\" OR \")})` : \"\";\n\n  return [\n    ean || reference,\n    \"caracter\u00edsticas imagem ficha t\u00e9cnica\",\n    domainFilter,\n  ]\n    .filter(Boolean)\n    .join(\" \");\n}\n\nexport function trustedSourcesConfig() {\n  return {\n    officialDomainsByBrand: OFFICIAL_DOMAINS_BY_BRAND,\n    verifiedRetailerDomains: VERIFIED_RETAILER_DOMAINS,\n  };\n}\n");
write(files.web, "import {\n  buildTrustedSearchQuery,\n  buildVerifiedSearchQuery,\n  inferBrandFromItem,\n  isOfficialDomain,\n  isVerifiedDomain,\n  sourcePriority,\n  normalizeDomain,\n} from \"./quoteDossierTrustedSources.js\";\n\nconst DEFAULT_TIMEOUT_MS = 12_000;\nconst MAX_HTML_BYTES = 1_500_000;\nconst MAX_IMAGE_BYTES = 4_000_000;\n\nconst enrichmentMemoryCache = new Map();\n\nfunction clean(value = \"\") {\n  return String(value || \"\")\n    .replace(/<[^>]+>/g, \" \")\n    .replace(/&nbsp;/gi, \" \")\n    .replace(/&amp;/gi, \"&\")\n    .replace(/&quot;/gi, '\"')\n    .replace(/&#39;/gi, \"'\")\n    .replace(/\\s+/g, \" \")\n    .trim();\n}\n\nfunction normalizeEan(value = \"\") {\n  return clean(value).replace(/\\D+/g, \"\");\n}\n\nfunction normalizeUrl(value = \"\", baseUrl = \"\") {\n  try {\n    return new URL(value, baseUrl || undefined).href;\n  } catch {\n    return \"\";\n  }\n}\n\nfunction userAgent() {\n  return process.env.QUOTE_DOSSIER_FETCH_USER_AGENT\n    || \"Mozilla/5.0 PromoPilotQuoteDossierBot/1.0 (+https://promopilot.pt)\";\n}\n\nasync function fetchWithTimeout(url, options = {}) {\n  const controller = new AbortController();\n  const timeout = setTimeout(() => controller.abort(), options.timeoutMs || DEFAULT_TIMEOUT_MS);\n\n  try {\n    return await fetch(url, {\n      ...options,\n      signal: controller.signal,\n      headers: {\n        \"user-agent\": userAgent(),\n        \"accept-language\": \"pt-PT,pt;q=0.9,en;q=0.6\",\n        ...(options.headers || {}),\n      },\n    });\n  } finally {\n    clearTimeout(timeout);\n  }\n}\n\nasync function fetchLimitedText(url) {\n  const response = await fetchWithTimeout(url, {\n    timeoutMs: DEFAULT_TIMEOUT_MS,\n    headers: {\n      accept: \"text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.5\",\n    },\n  });\n\n  if (!response.ok) {\n    throw new Error(`HTTP ${response.status}`);\n  }\n\n  const text = await response.text();\n  return text.slice(0, MAX_HTML_BYTES);\n}\n\nfunction extractMeta(html = \"\", property = \"\") {\n  const escaped = property.replace(/[.*+?^${}()|[\\]\\\\]/g, \"\\\\$&\");\n  const regexes = [\n    new RegExp(`<meta[^>]+property=[\"']${escaped}[\"'][^>]+content=[\"']([^\"']+)[\"'][^>]*>`, \"i\"),\n    new RegExp(`<meta[^>]+name=[\"']${escaped}[\"'][^>]+content=[\"']([^\"']+)[\"'][^>]*>`, \"i\"),\n    new RegExp(`<meta[^>]+content=[\"']([^\"']+)[\"'][^>]+property=[\"']${escaped}[\"'][^>]*>`, \"i\"),\n    new RegExp(`<meta[^>]+content=[\"']([^\"']+)[\"'][^>]+name=[\"']${escaped}[\"'][^>]*>`, \"i\"),\n  ];\n\n  for (const regex of regexes) {\n    const match = html.match(regex);\n    if (match?.[1]) return clean(match[1]);\n  }\n\n  return \"\";\n}\n\nfunction extractTitle(html = \"\") {\n  return clean(html.match(/<title[^>]*>([\\s\\S]*?)<\\/title>/i)?.[1] || \"\");\n}\n\nfunction extractJsonLd(html = \"\") {\n  const blocks = [];\n  const regex = /<script[^>]+type=[\"']application\\/ld\\+json[\"'][^>]*>([\\s\\S]*?)<\\/script>/gi;\n\n  for (const match of html.matchAll(regex)) {\n    const raw = match[1]?.trim();\n\n    if (!raw) continue;\n\n    try {\n      const parsed = JSON.parse(raw);\n      blocks.push(parsed);\n    } catch {\n      // Ignore malformed JSON-LD.\n    }\n  }\n\n  return blocks.flatMap((block) => {\n    if (Array.isArray(block)) return block;\n    if (Array.isArray(block?.[\"@graph\"])) return block[\"@graph\"];\n    return [block];\n  });\n}\n\nfunction findProductJsonLd(jsonLd = []) {\n  return jsonLd.find((entry) => {\n    const type = entry?.[\"@type\"];\n    if (Array.isArray(type)) return type.some((item) => String(item).toLowerCase() === \"product\");\n    return String(type || \"\").toLowerCase() === \"product\";\n  }) || null;\n}\n\nfunction normalizeImages(value) {\n  if (!value) return [];\n  if (Array.isArray(value)) return value.flatMap(normalizeImages);\n  if (typeof value === \"string\") return [value];\n  if (typeof value === \"object\" && value.url) return [value.url];\n  return [];\n}\n\nfunction normalizeAdditionalProperties(product = {}) {\n  const properties = product.additionalProperty || product.additionalProperties || [];\n\n  return (Array.isArray(properties) ? properties : [properties])\n    .map((property) => {\n      const name = clean(property?.name || property?.propertyID || \"\");\n      const value = clean(property?.value || property?.description || \"\");\n\n      if (!name && !value) return \"\";\n      if (!name) return value;\n      if (!value) return name;\n      return `${name}: ${value}`;\n    })\n    .filter(Boolean);\n}\n\nfunction extractFeatureCandidatesFromHtml(html = \"\") {\n  const candidates = [];\n  const listRegex = /<(?:li|td|p)[^>]*>([\\s\\S]*?)<\\/(?:li|td|p)>/gi;\n\n  for (const match of html.matchAll(listRegex)) {\n    const value = clean(match[1]);\n\n    if (\n      value.length >= 12\n      && value.length <= 150\n      && /(\\d|litro|l\\b|kg|cm|mm|w\\b|db|classe|capacidade|dimens|pot\u00eancia|wifi|no frost|airdry|hydroclean|indu\u00e7\u00e3o|encastre|programa|fun\u00e7\u00e3o)/i.test(value)\n    ) {\n      candidates.push(value);\n    }\n\n    if (candidates.length >= 20) break;\n  }\n\n  return candidates;\n}\n\nfunction unique(values = []) {\n  const seen = new Set();\n\n  return values\n    .map((value) => clean(value))\n    .filter(Boolean)\n    .filter((value) => {\n      const key = value.toLowerCase();\n      if (seen.has(key)) return false;\n      seen.add(key);\n      return true;\n    });\n}\n\nfunction buildCandidateFromHtml({ html, url, result, item }) {\n  const jsonLd = extractJsonLd(html);\n  const product = findProductJsonLd(jsonLd);\n  const title = clean(product?.name || extractMeta(html, \"og:title\") || extractTitle(html) || result?.title);\n  const description = clean(\n    product?.description\n    || extractMeta(html, \"og:description\")\n    || extractMeta(html, \"description\")\n    || result?.snippet\n    || \"\",\n  );\n\n  const productImages = normalizeImages(product?.image)\n    .map((imageUrl) => normalizeUrl(imageUrl, url))\n    .filter(Boolean);\n\n  const metaImage = normalizeUrl(extractMeta(html, \"og:image\"), url);\n  const imageUrls = unique([metaImage, ...productImages]).filter(Boolean);\n  const features = unique([\n    ...normalizeAdditionalProperties(product || {}),\n    ...extractFeatureCandidatesFromHtml(html),\n  ]).slice(0, 10);\n\n  const brand = clean(product?.brand?.name || product?.brand || inferBrandFromItem(item));\n  const sku = clean(product?.sku || product?.mpn || item.reference || \"\");\n  const gtin = normalizeEan(product?.gtin13 || product?.gtin || product?.gtin14 || item.ean || \"\");\n\n  return {\n    title,\n    description,\n    category: item.category || \"\",\n    reference: sku,\n    ean: gtin,\n    brand,\n    features,\n    imageUrls,\n    sourceUrl: url,\n    sourceDomain: normalizeDomain(url),\n    sourceType: isOfficialDomain(url, item) ? \"official\" : \"verified\",\n    confidence: isOfficialDomain(url, item) ? 0.9 : 0.72,\n  };\n}\n\nasync function searchSerper(query) {\n  const apiKey = process.env.SERPER_API_KEY || process.env.QUOTE_DOSSIER_SERPER_API_KEY;\n\n  if (!apiKey) return [];\n\n  const response = await fetchWithTimeout(\"https://google.serper.dev/search\", {\n    method: \"POST\",\n    timeoutMs: DEFAULT_TIMEOUT_MS,\n    headers: {\n      \"content-type\": \"application/json\",\n      \"x-api-key\": apiKey,\n    },\n    body: JSON.stringify({\n      q: query,\n      gl: process.env.QUOTE_DOSSIER_SEARCH_GL || \"pt\",\n      hl: process.env.QUOTE_DOSSIER_SEARCH_HL || \"pt-pt\",\n      num: 10,\n    }),\n  });\n\n  if (!response.ok) {\n    throw new Error(`Serper HTTP ${response.status}`);\n  }\n\n  const data = await response.json();\n  return Array.isArray(data?.organic) ? data.organic : [];\n}\n\nasync function searchBrave(query) {\n  const apiKey = process.env.BRAVE_SEARCH_API_KEY || process.env.QUOTE_DOSSIER_BRAVE_SEARCH_API_KEY;\n\n  if (!apiKey) return [];\n\n  const url = new URL(\"https://api.search.brave.com/res/v1/web/search\");\n  url.searchParams.set(\"q\", query);\n  url.searchParams.set(\"count\", \"10\");\n  url.searchParams.set(\"country\", process.env.QUOTE_DOSSIER_SEARCH_COUNTRY || \"PT\");\n  url.searchParams.set(\"search_lang\", process.env.QUOTE_DOSSIER_SEARCH_LANG || \"pt\");\n\n  const response = await fetchWithTimeout(url.href, {\n    timeoutMs: DEFAULT_TIMEOUT_MS,\n    headers: {\n      accept: \"application/json\",\n      \"x-subscription-token\": apiKey,\n    },\n  });\n\n  if (!response.ok) {\n    throw new Error(`Brave HTTP ${response.status}`);\n  }\n\n  const data = await response.json();\n  return (data?.web?.results || []).map((result) => ({\n    title: result.title,\n    link: result.url,\n    snippet: result.description,\n  }));\n}\n\nasync function searchVerifiedResults(item = {}) {\n  const queries = [\n    buildTrustedSearchQuery(item),\n    buildVerifiedSearchQuery(item),\n  ].filter(Boolean);\n\n  const allResults = [];\n\n  for (const query of queries) {\n    let results = [];\n\n    try {\n      results = await searchSerper(query);\n    } catch (error) {\n      console.warn(\"[quote-dossiers] Serper search failed:\", error?.message || error);\n    }\n\n    if (!results.length) {\n      try {\n        results = await searchBrave(query);\n      } catch (error) {\n        console.warn(\"[quote-dossiers] Brave search failed:\", error?.message || error);\n      }\n    }\n\n    allResults.push(...results);\n  }\n\n  return unique(\n    allResults\n      .filter((result) => result?.link && isVerifiedDomain(result.link, item))\n      .sort((a, b) => sourcePriority(a.link, item) - sourcePriority(b.link, item))\n      .map((result) => JSON.stringify({\n        title: clean(result.title),\n        link: result.link,\n        snippet: clean(result.snippet),\n      })),\n  )\n    .map((value) => JSON.parse(value))\n    .slice(0, Number(process.env.QUOTE_DOSSIER_MAX_SOURCE_PAGES || 4));\n}\n\nasync function imageToDataUrl(imageUrl = \"\", sourceUrl = \"\") {\n  const finalUrl = normalizeUrl(imageUrl, sourceUrl);\n\n  if (!finalUrl) return \"\";\n\n  const response = await fetchWithTimeout(finalUrl, {\n    timeoutMs: DEFAULT_TIMEOUT_MS,\n    headers: {\n      accept: \"image/avif,image/webp,image/png,image/jpeg,image/*;q=0.8\",\n    },\n  });\n\n  if (!response.ok) return \"\";\n\n  const contentType = response.headers.get(\"content-type\") || \"\";\n  if (!/^image\\/(png|jpe?g|webp|avif)/i.test(contentType)) return \"\";\n\n  const arrayBuffer = await response.arrayBuffer();\n\n  if (arrayBuffer.byteLength > MAX_IMAGE_BYTES) return \"\";\n\n  const mime = contentType.split(\";\")[0] || \"image/jpeg\";\n  return `data:${mime};base64,${Buffer.from(arrayBuffer).toString(\"base64\")}`;\n}\n\nasync function resolveBestImage(candidate = {}) {\n  for (const imageUrl of candidate.imageUrls || []) {\n    try {\n      const dataUrl = await imageToDataUrl(imageUrl, candidate.sourceUrl);\n      if (dataUrl) return dataUrl;\n    } catch {\n      // Try next image.\n    }\n  }\n\n  return \"\";\n}\n\nfunction mergeCandidateIntoItem(item = {}, candidate = {}, imageDataUrl = \"\") {\n  const features = unique([\n    ...(candidate.features || []),\n    ...(item.features || []),\n  ]).slice(0, 8);\n\n  return {\n    ...item,\n    title: clean(candidate.title || item.title || item.description || item.rawDescription),\n    description: clean(candidate.title || item.description || item.rawDescription),\n    category: clean(item.category || candidate.category || \"Equipamento\"),\n    reference: clean(item.reference || candidate.reference || \"\"),\n    ean: normalizeEan(item.ean || candidate.ean),\n    brand: clean(item.brand || candidate.brand || inferBrandFromItem(item)),\n    technicalDescription: clean(candidate.description || item.technicalDescription || item.description),\n    features,\n    imageDataUrl: item.imageDataUrl || imageDataUrl,\n    enrichment: {\n      status: candidate.sourceType === \"official\" ? \"official_match\" : \"verified_match\",\n      source: candidate.sourceType,\n      confidence: candidate.confidence || 0.7,\n      sourceUrl: candidate.sourceUrl,\n      sourceDomain: candidate.sourceDomain,\n      sourceLabel: candidate.sourceType === \"official\"\n        ? `Fonte oficial: ${candidate.sourceDomain}`\n        : `Fonte verificada: ${candidate.sourceDomain}`,\n    },\n  };\n}\n\nexport async function enrichItemFromVerifiedWeb(item = {}) {\n  const enabled = String(process.env.QUOTE_DOSSIER_WEB_ENRICHMENT || \"\").toLowerCase();\n\n  if (![\"1\", \"true\", \"yes\", \"on\"].includes(enabled)) {\n    return null;\n  }\n\n  const cacheKey = normalizeEan(item.ean) || clean(item.reference || item.description).toLowerCase();\n\n  if (cacheKey && enrichmentMemoryCache.has(cacheKey)) {\n    return enrichmentMemoryCache.get(cacheKey);\n  }\n\n  const results = await searchVerifiedResults(item);\n\n  for (const result of results) {\n    try {\n      const html = await fetchLimitedText(result.link);\n      const candidate = buildCandidateFromHtml({\n        html,\n        url: result.link,\n        result,\n        item,\n      });\n\n      if (!candidate.title && !candidate.description) continue;\n\n      const imageDataUrl = await resolveBestImage(candidate);\n      const enriched = mergeCandidateIntoItem(item, candidate, imageDataUrl);\n\n      if (cacheKey) enrichmentMemoryCache.set(cacheKey, enriched);\n\n      return enriched;\n    } catch (error) {\n      console.warn(\"[quote-dossiers] source enrichment failed:\", result.link, error?.message || error);\n    }\n  }\n\n  return null;\n}\n\nexport function webEnrichmentStatus() {\n  return {\n    enabled: [\"1\", \"true\", \"yes\", \"on\"].includes(String(process.env.QUOTE_DOSSIER_WEB_ENRICHMENT || \"\").toLowerCase()),\n    serper: Boolean(process.env.SERPER_API_KEY || process.env.QUOTE_DOSSIER_SERPER_API_KEY),\n    brave: Boolean(process.env.BRAVE_SEARCH_API_KEY || process.env.QUOTE_DOSSIER_BRAVE_SEARCH_API_KEY),\n    cacheSize: enrichmentMemoryCache.size,\n  };\n}\n");
